(49, 'PASSWORD_UPDATE', 'Password Updated', 'Your password has been updated', 'Password Updated', 'Hello {{name}},\\n\\nYour password has been successfully updated by an administrator.\\n\\nIf you did not request this change, please contact support immediately.\\n\\nBest regards,\\nThe Team', 'Hello {{name}}, your password has been updated by an administrator. Contact support if this was not requested.', 'Your account password has been updated.', NULL, 1, 1, NULL, NULL, NULL, 1, '2025-09-25 08:06:13', '2025-09-25 08:06:13'),
(50, 'TRANSFER_PIN_UPDATE', 'Transfer PIN Updated', 'Your transfer PIN has been updated', 'Transfer PIN Updated', 'Hello {{name}},\\n\\nYour transfer PIN has been successfully updated by an administrator.\\n\\nIf you did not request this change, please contact support immediately.\\n\\nBest regards,\\nThe Team', 'Hello {{name}}, your transfer PIN has been updated by an administrator. Contact support if this was not requested.', 'Your transfer PIN has been updated.', NULL, 1, 1, NULL, NULL, NULL, 1, '2025-09-25 08:07:11', '2025-09-25 08:07:11'),
(51, 'WITHDRAWAL_BLOCKED', 'Withdrawal Blocked', 'Withdrawal Request Blocked - {{status}}', NULL, '<div>Dear {{fullname}},</div>\r\n<div><br></div>\r\n<div>Your withdrawal request has been blocked due to account restrictions.</div>\r\n<div><br></div>\r\n<div><strong>Transaction Details:</strong></div>\r\n<div>Amount: {{amount}} {{site_currency}}</div>\r\n<div>Method: {{method_name}}</div>\r\n<div>Transaction ID: {{trx}}</div>\r\n<div>Date: {{time}}</div>\r\n<div><br></div>\r\n<div><strong>Restriction Status:</strong> {{status}}</div>\r\n<div><br></div>\r\n<div><strong>Reason:</strong></div>\r\n<div>{{reason}}</div>\r\n<div><br></div>\r\n<div>Please contact our support team if you have any questions regarding this restriction.</div>\r\n<div><br></div>\r\n<div>Best regards,<br>{{site_name}} Team</div>', 'Dear {{fullname}}, Your withdrawal request for {{amount}} {{site_currency}} has been blocked. Status: {{status}}. Reason: {{reason}}. Please contact support.', 'Your withdrawal request for {{amount}} {{site_currency}} has been blocked. Status: {{status}}. Please check your email for details.', '[\"status\",\"reason\",\"amount\",\"method_name\",\"trx\",\"time\",\"fullname\",\"site_currency\",\"site_name\"]', 1, 1, NULL, NULL, NULL, 1, '2025-10-03 07:09:46', '2025-10-03 07:09:46');

